// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

// ── TYPES: define local types and interfaces here ──
type ForecastDay = { day?: string; icon?: string; high?: number; low?: number };

// ── CONSTANTS: define constants, config, mappings here ──
const WEATHER_ICONS: Record<string, string> = {
  sunny: '☀️',
  'partly cloudy': '⛅',
  'partly-cloudy': '⛅',
  cloudy: '☁️',
  overcast: '☁️',
  'scattered clouds': '☁️',
  'few clouds': '⛅',
  rainy: '🌧️',
  rain: '🌧️',
  drizzle: '🌦️',
  'heavy rain': '⛈️',
  'heavy-rain': '⛈️',
  thunderstorm: '⛈️',
  snowy: '❄️',
  snow: '❄️',
  sleet: '🌨️',
  hail: '🌨️',
  windy: '💨',
  wind: '💨',
  foggy: '🌫️',
  fog: '🌫️',
  mist: '🌫️',
  default: '🌤️',
};

const getWeatherIcon = (condition: string | undefined): string => {
  if (!condition) return WEATHER_ICONS.default;
  const normalized = condition.toLowerCase().replace(/\s+/g, '-');
  return WEATHER_ICONS[normalized] || WEATHER_ICONS.default;
};

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function ForecastCard({ day, icon, high, low, unit }: ForecastDay & { unit: string }) {
  // Use 'icon' if it's a pre-built emoji, otherwise map from condition string
  const displayIcon =
    icon && icon.length === 1 && /\p{Emoji}/u.test(icon) ? icon : getWeatherIcon(icon || 'default');

  return (
    <Card
      padding={12}
      shadow="sm"
      border={false}
      radius="md"
      style={{ flex: 1, minWidth: '100px' }}
    >
      <Stack gap={8} align="center">
        <Text variant="label" align="center">
          {day || 'N/A'}
        </Text>
        <Text size="2xl">{displayIcon}</Text>
        <Stack gap={2} align="center">
          <Text variant="bodySmall" weight="semibold">
            {high}° {unit}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {low}° {unit}
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

function useComponent(props: Props) {
  // ── STATE: define useState hooks here ──
  // No additional state needed — all data comes from props

  // ── MEMOS: define useMemo for derived/computed values ──
  const weatherIcon = useMemo(() => getWeatherIcon(props.condition), [props.condition]);

  // ── CALLBACKS: define useCallback for event handlers ──
  // No callbacks needed for this display-only component

  return {
    weatherIcon,
  };
}
export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Weather in {props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current conditions and 5-day forecast
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
        <Card padding={32} shadow="md" radius="lg">
          <Stack gap={24}>
            {/* Current Temperature Section */}
            <Stack gap={16} align="center">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                {props.temperature}°{props.unit}
              </Text>
              <Stack gap={8} align="center">
                <Text size="3xl">{state.weatherIcon}</Text>
                <Text size="xl" weight="semibold">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <Divider orientation="horizontal" margin={12} />

            {/* Weather Details Grid */}
            <Stack gap={24} direction="horizontal" align="center" justify="center" wrap={true}>
              <Stack gap={4} align="center">
                <Icon name="droplet" size={20} color="var(--ggui-color-info-500, #06b6d4)" />
                <Text variant="label">Humidity</Text>
                <Text size="lg" weight="semibold">
                  {props.humidity}%
                </Text>
              </Stack>
              <Stack gap={4} align="center">
                <Icon name="wind" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Text variant="label">Wind Speed</Text>
                <Text size="lg" weight="semibold">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST SECTION */}
        <Stack gap={12}>
          <Heading level={3}>5-Day Forecast</Heading>
          <Stack gap={12} direction="horizontal" wrap={true}>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, idx) => (
                <ForecastCard
                  key={idx}
                  day={day.day}
                  icon={day.icon}
                  high={day.high}
                  low={day.low}
                  unit={props.unit}
                />
              ))
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No forecast data available
              </Text>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Select,
  Checkbox,
  Toggle,
  RadioGroup,
  Slider,
  Badge,
  Spinner,
  Avatar,
  Alert,
  Progress,
  Image,
  Icon,
  Link,
  Tooltip,
  Table,
  Tabs,
  Toast,
  Accordion,
} from '@ggui-ai/design/primitives';
import {
  SearchField,
  FormField,
  MenuItem,
  Tag,
  Dropdown,
  Autocomplete,
  Breadcrumb,
  Pagination,
} from '@ggui-ai/design/components';
import {
  Header,
  Sidebar,
  CardGrid,
  CommentThread,
  DataTable,
  ChatWindow,
  NavigationBar,
  FileUploader,
  UserProfileCard,
  NotificationCenter,
  Modal,
  CommandPalette,
  Footer,
  Hero,
} from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
};

// ── TYPES: define local types and interfaces here ──
interface SurveyAnswers {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
}

// ── CONSTANTS: define constants, config, mappings here ──
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const TOTAL_STEPS = 4;

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function StepIndicator({ current, total }: { current: number; total: number }) {
  const progress = (current / total) * 100;
  return (
    <Stack gap={8}>
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        Step {current} of {total}
      </Text>
      <Progress value={progress} max={100} size="md" />
    </Stack>
  );
}

function NameEmailStep({ name, email, onNameChange, onEmailChange, errors }: any) {
  return (
    <Stack gap={12}>
      <Input
        label="Name"
        value={name}
        onChange={onNameChange}
        placeholder="Enter your name"
        required
        error={errors.name}
      />
      <Input
        label="Email"
        type="email"
        value={email}
        onChange={onEmailChange}
        placeholder="Enter your email"
        required
        error={errors.email}
      />
    </Stack>
  );
}

function SatisfactionStep({ value, labels, onChange }: any) {
  return (
    <RadioGroup
      label="How satisfied are you with our service?"
      value={String(value || '')}
      onChange={(v) => onChange(parseInt(v))}
      options={labels.map((label: string, idx: number) => ({
        value: String(idx + 1),
        label: label,
      }))}
      direction="vertical"
    />
  );
}

function FeaturesStep({ selected, features, onChange }: any) {
  return (
    <Stack gap={8}>
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        Which features are you interested in?
      </Text>
      <Stack gap={6}>
        {features.map((feature: string) => (
          <Checkbox
            key={feature}
            label={feature}
            checked={selected.includes(feature)}
            onChange={(checked) => {
              if (checked) {
                onChange([...selected, feature]);
              } else {
                onChange(selected.filter((f: string) => f !== feature));
              }
            }}
          />
        ))}
      </Stack>
    </Stack>
  );
}

function CommentsStep({ value, onChange }: any) {
  return (
    <TextArea
      label="Additional Comments"
      value={value}
      onChange={onChange}
      placeholder="Share any additional feedback..."
      rows={6}
      maxLength={500}
      showCount
    />
  );
}

function ReviewStep({ answers }: { answers: SurveyAnswers }) {
  return (
    <Stack gap={12}>
      <Alert variant="info" title="Review Your Answers">
        Please review your responses before submitting.
      </Alert>
      <Card padding={16} shadow="sm">
        <Stack gap={8}>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Name
            </Text>
            <Text>{answers.name}</Text>
          </Box>
          <Divider orientation="horizontal" margin={8} />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Email
            </Text>
            <Text>{answers.email}</Text>
          </Box>
          <Divider orientation="horizontal" margin={8} />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Satisfaction Rating
            </Text>
            <Text>
              {answers.satisfaction} / {props.satisfactionLabels.length}
            </Text>
          </Box>
          <Divider orientation="horizontal" margin={8} />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interested Features
            </Text>
            <Stack gap={4} direction="horizontal" wrap>
              {answers.features.length > 0 ? (
                answers.features.map((f) => (
                  <Badge key={f} variant="primary">
                    {f}
                  </Badge>
                ))
              ) : (
                <Text variant="caption">None selected</Text>
              )}
            </Stack>
          </Box>
          <Divider orientation="horizontal" margin={8} />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Comments
            </Text>
            <Text>{answers.comments || '(No comments)'}</Text>
          </Box>
        </Stack>
      </Card>
    </Stack>
  );
}

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // ── STATE: define useState hooks here ──
  const [currentStep, setCurrentStep] = useState(1);
  const [answers, setAnswers] = useState<SurveyAnswers>({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  // ── MEMOS: define useMemo for derived/computed values ──
  const isStep1Valid = answers.name.trim() !== '' && EMAIL_REGEX.test(answers.email);

  // ── CALLBACKS: define useCallback for event handlers ──
  const validateStep1 = useCallback(() => {
    const newErrors: Record<string, string> = {};
    if (!answers.name.trim()) newErrors.name = 'Name is required';
    if (!EMAIL_REGEX.test(answers.email)) newErrors.email = 'Please enter a valid email address';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [answers.name, answers.email]);

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !validateStep1()) return;
    if (currentStep < TOTAL_STEPS) {
      setCurrentStep(currentStep + 1);
    } else if (currentStep === TOTAL_STEPS) {
      setCurrentStep(TOTAL_STEPS + 1); // Go to review
    }
  }, [currentStep, validateStep1]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    submit(answers);
  }, [answers, submit]);

  return {
    currentStep,
    answers,
    setAnswers,
    errors,
    isStep1Valid,
    handleNext,
    handleBack,
    handleSubmit,
  };
}

export default function Component(props: Props) {
  const {
    currentStep,
    answers,
    setAnswers,
    errors,
    isStep1Valid,
    handleNext,
    handleBack,
    handleSubmit,
  } = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Customer Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Help us improve by sharing your feedback
          </Text>
        </Stack>

        {/* PROGRESS BAR & STEP INDICATOR */}
        <StepIndicator
          current={currentStep}
          total={currentStep === 5 ? TOTAL_STEPS : TOTAL_STEPS}
        />

        {/* CONTENT */}
        <Card padding={24} shadow="md">
          <Stack gap={20}>
            {currentStep === 1 && (
              <NameEmailStep
                name={answers.name}
                email={answers.email}
                onNameChange={(v: string) => setAnswers({ ...answers, name: v })}
                onEmailChange={(v: string) => setAnswers({ ...answers, email: v })}
                errors={errors}
              />
            )}
            {currentStep === 2 && (
              <SatisfactionStep
                value={answers.satisfaction}
                labels={props.satisfactionLabels}
                onChange={(v: number) => setAnswers({ ...answers, satisfaction: v })}
              />
            )}
            {currentStep === 3 && (
              <FeaturesStep
                selected={answers.features}
                features={props.featureOptions}
                onChange={(v: string[]) => setAnswers({ ...answers, features: v })}
              />
            )}
            {currentStep === 4 && (
              <CommentsStep
                value={answers.comments}
                onChange={(v: string) => setAnswers({ ...answers, comments: v })}
              />
            )}
            {currentStep === 5 && <ReviewStep answers={answers} />}
          </Stack>
        </Card>

        {/* NAVIGATION BUTTONS */}
        <Row gap={12} justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>
            Back
          </Button>
          <Stack direction="horizontal" gap={8}>
            {currentStep < 5 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={currentStep === 1 && !isStep1Valid}
              >
                Next
              </Button>
            )}
            {currentStep === 5 && (
              <Button variant="primary" onClick={handleSubmit}>
                Submit
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

