import React, { useState, useCallback, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Select,
  Checkbox,
  Toggle,
  RadioGroup,
  Slider,
  Badge,
  Spinner,
  Avatar,
  Alert,
  Progress,
  Image,
  Icon,
  Link,
  Tooltip,
  Table,
  Tabs,
  Toast,
  Accordion,
} from '@ggui-ai/design/primitives';
import {
  SearchField,
  FormField,
  MenuItem,
  Tag,
  Dropdown,
  Autocomplete,
  Breadcrumb,
  Pagination,
} from '@ggui-ai/design/components';
import {
  Header,
  Sidebar,
  CardGrid,
  CommentThread,
  DataTable,
  ChatWindow,
  NavigationBar,
  FileUploader,
  UserProfileCard,
  NotificationCenter,
  Modal,
  CommandPalette,
  Footer,
  Hero,
} from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';

// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = {
  action: string;
  taskId: string;
  data: { column?: string; title?: string; priority?: string };
};

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = {
  action?: 'create' | 'move' | 'edit' | 'delete';
  task?: {
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  };
};

// ── TYPES: define local types and interfaces here ──
interface TaskWithLocals extends NonNullable<Props['tasks'][number]> {
  isEditing?: boolean;
  editTitle?: string;
}

// ── CONSTANTS: define constants, config, mappings here ──
const PRIORITY_COLORS: Record<
  'low' | 'medium' | 'high',
  'default' | 'primary' | 'warning' | 'error'
> = {
  low: 'default',
  medium: 'primary',
  high: 'error',
};

const PRIORITY_LABELS: Record<'low' | 'medium' | 'high', string> = {
  low: 'Low',
  medium: 'Medium',
  high: 'High',
};

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──
interface TaskCardProps {
  task: TaskWithLocals;
  onEdit: (taskId: string, title: string) => void;
  onMove: (taskId: string, targetColumn: string) => void;
  onToggleEdit: (taskId: string) => void;
  columns: Props['columns'];
}

function TaskCard({ task, onEdit, onMove, onToggleEdit, columns }: TaskCardProps) {
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
        onEdit(task.id || '', task.editTitle || task.title || '');
        onToggleEdit(task.id || '');
      } else if (e.key === 'Escape') {
        onToggleEdit(task.id || '');
      }
    },
    [task.id, task.editTitle, task.title, onEdit, onToggleEdit],
  );

  return (
    <Card padding={12} shadow="sm" radius="md">
      <Stack gap={8}>
        {task.isEditing ? (
          <Input
            label="Edit task title"
            value={task.editTitle || ''}
            onChange={(val) => onEdit(task.id || '', val)}
            placeholder="Task title"
            onKeyDown={handleKeyDown}
          />
        ) : (
          <Text
            variant="body"
            style={{ fontWeight: 'var(--ggui-font-weight-medium, 500)' }}
            is="span"
            as={Clickable}
            onClick={(e) => {
              if ((e as any).detail === 2) onToggleEdit(task.id || '');
            }}
          >
            {task.title}
          </Text>
        )}
        <Stack direction="horizontal" gap={8} align="center">
          {task.priority && (
            <Badge variant={PRIORITY_COLORS[task.priority]} size="sm">
              {PRIORITY_LABELS[task.priority]}
            </Badge>
          )}
          {task.assignee && <Avatar name={task.assignee} size={24} shape="circle" />}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {new Date(task.dueDate).toLocaleDateString()}
            </Text>
          )}
        </Stack>
        {task.isEditing ? (
          <Stack direction="horizontal" gap={8}>
            <Button
              variant="primary"
              size="xs"
              onClick={() => {
                onEdit(task.id || '', task.editTitle || task.title || '');
                onToggleEdit(task.id || '');
              }}
            >
              Save
            </Button>
            <Button variant="ghost" size="xs" onClick={() => onToggleEdit(task.id || '')}>
              Cancel
            </Button>
          </Stack>
        ) : (
          <Stack direction="horizontal" gap={8}>
            <Button variant="ghost" size="xs" onClick={() => onToggleEdit(task.id || '')}>
              Edit
            </Button>
            <Dropdown
              trigger={
                <Button variant="ghost" size="xs">
                  Move
                </Button>
              }
              options={columns.map((col) => ({ value: col.id || '', label: col.name || '' }))}
              value={task.column || ''}
              onChange={(col) => onMove(task.id || '', col)}
              placement="bottom-start"
            />
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // ── STATE: define useState hooks here ──
  const [tasks, setTasks] = useState<TaskWithLocals[]>(props.tasks || []);
  const [showAddForm, setShowAddForm] = useState<Record<string, boolean>>({});
  const [newTaskTitles, setNewTaskTitles] = useState<Record<string, string>>({});
  const [newTaskPriorities, setNewTaskPriorities] = useState<
    Record<string, 'low' | 'medium' | 'high'>
  >({});

  // Sync props changes to state
  React.useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle stream updates from other users
  React.useEffect(() => {
    if (taskChanged.latest && taskChanged.latest.task) {
      const changedTask = taskChanged.latest.task;
      if (taskChanged.latest.action === 'create') {
        setTasks((prev) => [
          ...prev,
          { ...changedTask, id: changedTask.id || `task-${Date.now()}` },
        ]);
      } else if (taskChanged.latest.action === 'move' || taskChanged.latest.action === 'edit') {
        setTasks((prev) =>
          prev.map((t) => (t.id === changedTask.id ? { ...t, ...changedTask } : t)),
        );
      } else if (taskChanged.latest.action === 'delete') {
        setTasks((prev) => prev.filter((t) => t.id !== changedTask.id));
      }
    }
  }, [taskChanged.latest]);

  // ── MEMOS: define useMemo for derived/computed values ──
  const tasksByColumn = React.useMemo(() => {
    const grouped: Record<string, TaskWithLocals[]> = {};
    (props.columns || []).forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  const taskStats = React.useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleMoveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t)));
      taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    },
    [taskUpdate],
  );

  const handleCreateTask = useCallback(
    (columnId: string) => {
      const title = newTaskTitles[columnId] || 'Untitled Task';
      const priority = newTaskPriorities[columnId] || 'medium';
      const newTask: TaskWithLocals = {
        id: `task-${Date.now()}`,
        title,
        priority,
        column: columnId,
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: { column: columnId, title, priority },
      });
      setNewTaskTitles((prev) => ({ ...prev, [columnId]: '' }));
      setNewTaskPriorities((prev) => ({ ...prev, [columnId]: 'medium' }));
      setShowAddForm((prev) => ({ ...prev, [columnId]: false }));
    },
    [newTaskTitles, newTaskPriorities, taskUpdate],
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle, editTitle: undefined } : t)),
      );
      taskUpdate({
        action: 'edit',
        taskId,
        data: { column: tasks.find((t) => t.id === taskId)?.column || '', title: newTitle },
      });
    },
    [taskUpdate, tasks],
  );

  const handleToggleEditTask = useCallback((taskId: string) => {
    setTasks((prev) =>
      prev.map((t) =>
        t.id === taskId ? { ...t, isEditing: !t.isEditing, editTitle: t.title } : t,
      ),
    );
  }, []);

  return {
    tasks,
    tasksByColumn,
    taskStats,
    showAddForm,
    newTaskTitles,
    newTaskPriorities,
    setShowAddForm,
    setNewTaskTitles,
    setNewTaskPriorities,
    handleMoveTask,
    handleCreateTask,
    handleEditTask,
    handleToggleEditTask,
  };
}

