function useComponent(props: Props) {
  // ── STATE: define useState hooks here ──
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // ── MEMOS: define useMemo for derived/computed values ──
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) => el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query),
    );
  }, [searchQuery, props.elements]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleSearch = useCallback((query: string) => {
    setSearchQuery(query);
  }, []);

  const handleElementClick = useCallback((element: ElementData) => {
    setSelectedElement(element);
  }, []);

  const handleClearSelection = useCallback(() => {
    setSelectedElement(null);
  }, []);

  return {
    searchQuery,
    handleSearch,
    filteredElements,
    selectedElement,
    handleElementClick,
    handleClearSelection,
    uniqueCategories,
  };
}

