function useComponent(props: Props) {
  // Wire hooks
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Derived values
  const stock = props.product.stock || 0;
  const isOutOfStock = stock === 0;
  const canDecrement = quantity > 1;
  const canIncrement = quantity < stock;

  // Event handlers
  const handleIncrement = useCallback(() => {
    setQuantity((q) => Math.min(q + 1, stock));
  }, [stock]);

  const handleDecrement = useCallback(() => {
    setQuantity((q) => Math.max(q - 1, 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
      setQuantity(1);
    }
  }, [props.product.id, quantity, addToCart]);

  return {
    quantity,
    setQuantity,
    activeTab,
    setActiveTab,
    stock,
    isOutOfStock,
    canDecrement,
    canIncrement,
    handleIncrement,
    handleDecrement,
    handleAddToCart,
  };
}

