            <Row gap={8} align="center">
              <Row gap={4}>{renderStars(product.rating)}</Row>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                ({product.reviewCount || 0} reviews)
              </Text>
            </Row>
            <Badge variant={state.isOutOfStock ? 'error' : 'success'} size="md">
              {state.isOutOfStock ? 'Out of Stock' : state.stock < 5 ? 'Low Stock' : 'In Stock'}
            </Badge>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={state.activeTab}
          onChange={state.setActiveTab}
          variant="line"
          size="md"
        />

        {/* BOTTOM SECTION: Quantity & Add to Cart */}
        <Stack gap={16} direction="horizontal" align="center">
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="label">Quantity:</Text>
            <Button
              variant="outline"
              size="sm"
              onClick={state.handleDecrement}
              disabled={!state.canDecrement}
            >
              −
            </Button>
            <Box
              style={{
                minWidth: '40px',
                textAlign: 'center',
                padding: '8px',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Text variant="body">{state.quantity}</Text>
            </Box>
            <Button
              variant="outline"
              size="sm"
              onClick={state.handleIncrement}
              disabled={!state.canIncrement}
            >
              +
            </Button>
          </Stack>
          <Button
            variant="primary"
            size="lg"
            onClick={state.handleAddToCart}
            disabled={state.isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Select,
  Checkbox,
  Toggle,
  RadioGroup,
  Slider,
  Badge,
  Spinner,
  Avatar,
  Alert,
  Progress,
  Image,
  Icon,
  Link,
  Tooltip,
  Table,
  Tabs,
  Toast,
  Accordion,
} from '@ggui-ai/design/primitives';
import {
  SearchField,
  FormField,
  MenuItem,
  Tag,
  Dropdown,
  Autocomplete,
  Breadcrumb,
  Pagination,
} from '@ggui-ai/design/components';
import {
  Header,
  Sidebar,
  CardGrid,
  CommentThread,
  DataTable,
  ChatWindow,
  NavigationBar,
  FileUploader,
  UserProfileCard,
  NotificationCenter,
  Modal,
  CommandPalette,
  Footer,
  Hero,
} from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';

// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

// ── TYPES: define local types and interfaces here ──
interface ChatMessage {
  sender: string;
  text: string;
  timestamp: string;
}

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // ── STATE: define useState hooks here ──
  const [allMessages, setAllMessages] = useState<ChatMessage[]>(
    props.messages.map((m) => ({
      sender: m.sender || 'Unknown',
      text: m.text || '',
      timestamp: m.timestamp || new Date().toISOString(),
    })),
  );
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream and auto-scroll
  React.useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [
        ...prev,
        {
          sender: message.latest!.sender || 'Unknown',
          text: message.latest!.text || '',
          timestamp: message.latest!.timestamp || new Date().toISOString(),
        },
      ]);
    }
  }, [message.latest]);

  // Auto-scroll to bottom on new messages
  React.useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleSendMessage = useCallback(() => {
    if (!inputValue.trim()) return;
    const payload: ActionSendMessagePayload = {
      text: inputValue,
      timestamp: new Date().toISOString(),
    };
    sendMessage(payload);
    setInputValue('');
  }, [inputValue, sendMessage]);

  const handleKeyPress = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage],
  );

  // Get active typing indicator
  const typingUser = typing.latest?.active ? typing.latest.sender : null;

  return {
    allMessages,
    inputValue,
    setInputValue,
    handleSendMessage,
    handleKeyPress,
    typingUser,
    messagesEndRef,
  };
}

export default function Component(props: Props) {
  const {
    allMessages,
    inputValue,
    setInputValue,
    handleSendMessage,
    handleKeyPress,
    typingUser,
    messagesEndRef,
  } = useComponent(props);

  return (
    <Stack gap={16} style={{ height: '100%', minHeight: '600px' }}>
      {/* HEADER */}
      <Card shadow="md" padding={16} border={true} radius="lg">
        <Stack direction="horizontal" justify="between" align="center" gap={16}>
          <Stack direction="horizontal" align="center" gap={12}>
            <Heading level={3}>{props.title}</Heading>
            <Badge variant="primary" size="sm" pill>
              {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
            </Badge>
          </Stack>
          {typingUser && (
            <Stack direction="horizontal" align="center" gap={8}>
              <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {typingUser} is typing...
              </Text>
            </Stack>
          )}
        </Stack>
      </Card>

      {/* MESSAGE LIST */}
      <Card
        shadow="sm"
        padding={0}
        border={true}
        radius="lg"
        style={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}
      >
        <Stack
          gap={12}
          style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}
        >
          {allMessages.length === 0 ? (
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
              style={{ marginTop: '24px' }}
            >
              No messages yet
            </Text>
          ) : (
            allMessages.map((msg, idx) => {
              const isOwnMessage = msg.sender === props.currentUser;
              const prevMsg = idx > 0 ? allMessages[idx - 1] : null;
              const isConsecutive = prevMsg && prevMsg.sender === msg.sender;
              const timestamp = new Date(msg.timestamp).toLocaleTimeString([], {
                hour: '2-digit',
                minute: '2-digit',
              });
              return (
                <Stack key={idx} gap={4} align={isOwnMessage ? 'end' : 'start'}>
                  {!isConsecutive && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {msg.sender}
                    </Text>
                  )}
                  <Box
                    padding={12}
                    background={
                      isOwnMessage
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                    }
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    style={{ maxWidth: '60%', wordWrap: 'break-word' }}
                  >
                    <Text
                      variant="body"
                      color={isOwnMessage ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isOwnMessage
                          ? 'rgba(255,255,255,0.7)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
                    >
                      {timestamp}
                    </Text>
                  </Box>
                </Stack>
              );
            })
          )}
          <Box ref={messagesEndRef} />
        </Stack>

        {/* INPUT AREA */}
        <Stack gap={8}>
          <Stack direction="horizontal" gap={8}>
            <TextArea
              label="Message"
              value={inputValue}
              onChange={setInputValue}
              onKeyDown={handleKeyPress}
              placeholder="Type a message (Enter to send, Shift+Enter for newline)"
              rows={2}
            />
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!inputValue.trim()}
              style={{ alignSelf: 'flex-end', minWidth: '120px' }}
            >
              Send
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );
}

