  Toggle,
  RadioGroup,
  Slider,
  Badge,
  Spinner,
  Avatar,
  Alert,
  Progress,
  Image,
  Icon,
  Link,
  Tooltip,
  Table,
  Tabs,
  Toast,
  Accordion,
} from '@ggui-ai/design/primitives';
import {
  SearchField,
  FormField,
  MenuItem,
  Tag,
  Dropdown,
  Autocomplete,
  Breadcrumb,
  Pagination,
} from '@ggui-ai/design/components';
import {
  Header,
  Sidebar,
  CardGrid,
  CommentThread,
  DataTable,
  ChatWindow,
  NavigationBar,
  FileUploader,
  UserProfileCard,
  NotificationCenter,
  Modal,
  CommandPalette,
  Footer,
  Hero,
} from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';

// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = {
  symbol?: string;
  price?: number;
  change?: number;
  changePercent?: number;
};

/** Stream event: Market open/closed status update */
type StreamMarketStatus = {
  status?: 'open' | 'closed' | 'pre-market' | 'after-hours';
  timestamp?: string;
};

// ── TYPES: define local types and interfaces here ──
interface StockData {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
}

// ── CONSTANTS: define constants, config, mappings here ──
const FLASH_ANIMATION_DURATION = 600;
// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

interface StockCardProps {
  stock: StockData;
  isFlashing?: boolean;
  onClick?: () => void;
  onKeyDown?: (e: React.KeyboardEvent) => void;
}
function StockCard({ stock, isFlashing, onClick, onKeyDown }: StockCardProps) {
  const isPositive = stock.change >= 0;
  const arrowIcon = isPositive ? '▲' : '▼';
  const textColor = isPositive
    ? 'var(--ggui-color-success-600, #16a34a)'
    : 'var(--ggui-color-error-600, #dc2626)';
  const borderColor = isPositive
    ? 'var(--ggui-color-success-200, #bbf7d0)'
    : 'var(--ggui-color-error-200, #fecaca)';

  const animationStyle = isFlashing
    ? {
        animation: `flashHighlight ${FLASH_ANIMATION_DURATION}ms ease-in-out`,
      }
    : {};

  return (
    <>
      <style>{`
        @keyframes flashHighlight {
          0% { background-color: transparent; }
          50% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
          100% { background-color: transparent; }
        }
      `}</style>
      <Card
        as={Hoverable}
        hoverStyle={{
          boxShadow: 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))',
          transform: 'translateY(-2px)',
          transition: 'all 200ms ease-in-out',
        }}
        shadow="md"
        padding={16}
        border={true}
        radius="lg"
        style={{
          borderColor: borderColor,
          borderWidth: '2px',
          borderStyle: 'solid',
          cursor: 'pointer',
          transition: 'all 200ms ease-in-out',
          ...animationStyle,
        }}
        onClick={onClick}
        onKeyDown={onKeyDown}
        role="button"
        tabIndex={0}
      >
        <Stack gap={8} align="start">
          <Text
            variant="overline"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {stock.symbol}
          </Text>
          <Text variant="body" size="sm" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {stock.name}
          </Text>
          <Divider orientation="horizontal" margin={8} />
          <Text variant="body" size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            ${stock.price.toFixed(2)}
          </Text>
          <Stack direction="horizontal" gap={4} align="center">
            <Text variant="body" size="base" color={textColor} weight="semibold">
              {isPositive ? '+' : ''}
              {stock.change.toFixed(2)}
            </Text>
            <Text variant="body" size="base" color={textColor} weight="semibold">
              {arrowIcon} {stock.changePercent.toFixed(2)}%
            </Text>
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

function useComponent(props: Props) {
  // ── STATE: define useState hooks here ──
  const [stocks, setStocks] = useState<StockData[]>(() => {
    return props.stocks.map((s) => ({
      symbol: s.symbol || '',
      name: s.name || '',
      price: s.price || 0,
      change: s.change || 0,
      changePercent: s.changePercent || 0,
    }));
  });
  const [lastUpdateTime, setLastUpdateTime] = useState(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());
  const [selectedSymbol, setSelectedSymbol] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [marketStatusInfo, setMarketStatusInfo] = useState<StreamMarketStatus | null>(null);
  const isInitialMountRef = useRef(true);

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // ── MEMOS: define useMemo for derived/computed values ──
  // Real-time timestamp updates (every second)
  useEffect(() => {
    const interval = setInterval(() => {
      setLastUpdateTime(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Merge stream updates into stocks state with flash animation
  useEffect(() => {
    if (priceUpdate.latest && !isInitialMountRef.current) {
      try {
        setStocks((prevStocks) => {
          const updated = prevStocks.map((stock) =>
            stock.symbol === priceUpdate.latest?.symbol
              ? {
                  ...stock,
                  price: priceUpdate.latest.price ?? stock.price,
                  change: priceUpdate.latest.change ?? stock.change,
                  changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
                }
              : stock,
          );
          return updated;
        });

        // Trigger flash animation
        if (priceUpdate.latest.symbol) {
          setFlashingSymbols((prev) => new Set(prev).add(priceUpdate.latest.symbol!));
          setTimeout(() => {
            setFlashingSymbols((prev) => {
              const next = new Set(prev);
              next.delete(priceUpdate.latest.symbol!);
              return next;
            });
          }, FLASH_ANIMATION_DURATION);
        }
      } catch (err) {
        setError('Failed to update stock price');
      }
    }
    isInitialMountRef.current = false;
  }, [priceUpdate.latest]);

  // Update market status display
  useEffect(() => {
    if (marketStatus.latest) {
      try {
        setMarketStatusInfo(marketStatus.latest);
        setError(null);
      } catch (err) {
        setError('Failed to update market status');
      }
    }
  }, [marketStatus.latest]);

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleStockClick = useCallback((symbol: string) => {
    setSelectedSymbol(symbol);
  }, []);

  const handleStockKeyDown = useCallback(
    (e: React.KeyboardEvent, symbol: string) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        handleStockClick(symbol);
      }
    },
    [handleStockClick],
  );

  return {
    stocks,
    lastUpdateTime,
    flashingSymbols,
    selectedSymbol,
    marketStatusInfo,
    error,
    handleStockClick,
    handleStockKeyDown,
  };
}

