// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
};

// ── TYPES: define local types and interfaces here ──
type Step = 1 | 2 | 3;

interface WizardState {
  currentStep: Step;
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

// ── CONSTANTS: define constants, config, mappings here ──
const THEME_OPTIONS = [
  { value: 'light', label: 'Light' },
  { value: 'dark', label: 'Dark' },
];

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function StepIndicator({ currentStep, totalSteps }: { currentStep: Step; totalSteps: number }) {
  return (
    <Stack gap={12}>
      <Stack direction="horizontal" justify="between" align="center" gap={8}>
        <Stack direction="horizontal" gap={8} align="center">
          {[1, 2, 3].map((step) => (
            <Stack key={step} direction="horizontal" align="center" gap={4}>
              <Badge variant={currentStep >= step ? 'primary' : 'default'} size="md" pill>
                {step}
              </Badge>
              {step < totalSteps && (
                <Box
                  style={{
                    width: '32px',
                    height: '2px',
                    backgroundColor:
                      currentStep > step
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-outline, #d4d4d8)',
                    transition: 'background-color 200ms ease-in-out',
                  }}
                />
              )}
            </Stack>
          ))}
        </Stack>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {currentStep} of {totalSteps}
        </Text>
      </Stack>
      <Progress value={(currentStep / totalSteps) * 100} variant="default" size="sm" />
    </Stack>
  );
}

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // ── STATE: define useState hooks here ──
  const [state, setState] = useState<WizardState>({
    currentStep: 1,
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar:
      props.initialProfile.avatar || (props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''),
    role: props.initialProfile.role || (props.roleOptions.length > 0 ? props.roleOptions[0] : ''),
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleNext = useCallback(() => {
    if (state.currentStep < 3) {
      setState((prev) => ({ ...prev, currentStep: (prev.currentStep + 1) as Step }));
    }
  }, [state.currentStep]);

  const handleBack = useCallback(() => {
    if (state.currentStep > 1) {
      setState((prev) => ({ ...prev, currentStep: (prev.currentStep - 1) as Step }));
    }
  }, [state.currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name: state.name,
      email: state.email,
      avatar: state.avatar,
      role: state.role,
      emailNotifications: state.emailNotifications,
      theme: state.theme,
    });
  }, [state, complete]);

  const isStep1Valid =
    state.name.trim().length > 0 &&
    /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(state.email) &&
    state.avatar.trim().length > 0;
  const isNextDisabled = state.currentStep === 1 && !isStep1Valid;

  return { state, setState, handleNext, handleBack, handleComplete, isNextDisabled };
}

